import{_ as i,c as t,o as a,aN as e}from"./chunks/framework.CqA5BTDU.js";const c=JSON.parse('{"title":"进程管理","description":"","frontmatter":{},"headers":[],"relativePath":"01.Linux基础/07-进程管理.md","filePath":"01.Linux基础/07-进程管理.md","lastUpdated":null}'),n={name:"01.Linux基础/07-进程管理.md"};function p(d,s,h,l,k,r){return a(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="进程管理" tabindex="-1">进程管理 <a class="header-anchor" href="#进程管理" aria-label="Permalink to &quot;进程管理&quot;">​</a></h1><p>服务出问题时，排查通常从进程是否存在、资源占用是否异常、由谁启动、受什么管理器管开始。</p><h2 id="一、进程基础概念" tabindex="-1">一、进程基础概念 <a class="header-anchor" href="#一、进程基础概念" aria-label="Permalink to &quot;一、进程基础概念&quot;">​</a></h2><p>进程是正在运行的程序实例。一个程序可以启动多个进程，每个进程有唯一的 PID（进程 ID）。进程可以继续创建子进程，形成父子关系——排查时不能只看命令名，还要看 PID、PPID（父进程 ID）、运行用户和启动来源。</p><p>查看当前 Shell 自己的进程信息：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> $$</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">            # 当前 Shell 的 PID</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ps</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> $$</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 查看该进程详情</span></span></code></pre></div><p>查看进程树（父子关系）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pstree</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span></span></code></pre></div><p><code>pstree</code> 不是默认安装的：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> psmisc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # RHEL 系</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> psmisc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # Debian 系</span></span></code></pre></div><p>进程由谁启动直接决定排查入口。systemd 拉起的进程、Shell 手动启动的进程、supervisor 托管的进程、容器运行时管理的进程——它们的日志位置、重启策略、环境变量都不同。</p><h2 id="二、ps-查看进程" tabindex="-1">二、ps 查看进程 <a class="header-anchor" href="#二、ps-查看进程" aria-label="Permalink to &quot;二、ps 查看进程&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ps</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aux</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # BSD 风格，显示所有用户的所有进程</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ps</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ef</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # Unix 风格，功能类似</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ps</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aux</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span></span></code></pre></div><p>查看指定 PID 的进程，并只显示关心的字段：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ps</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1234</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pid,ppid,user,stat,pcpu,pmem,cmd</span></span></code></pre></div><p>常用输出字段：</p><table tabindex="0"><thead><tr><th>字段</th><th>含义</th></tr></thead><tbody><tr><td>PID</td><td>进程 ID</td></tr><tr><td>PPID</td><td>父进程 ID</td></tr><tr><td>USER</td><td>进程的运行用户</td></tr><tr><td>STAT</td><td>进程状态（R=运行中、S=休眠、D=不可中断睡眠、Z=僵尸）</td></tr><tr><td>%CPU</td><td>CPU 使用百分比</td></tr><tr><td>%MEM</td><td>内存使用百分比</td></tr><tr><td>CMD</td><td>启动命令行</td></tr></tbody></table><p><code>CMD</code> 列可能被终端宽度截断。要看完整启动命令，直接读 <code>/proc/PID/cmdline</code>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;\\0&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39; &#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/proc/1234/cmdline</span></span></code></pre></div><p><code>/proc/PID/cmdline</code> 中的参数以 null 字符分隔，<code>tr</code> 把它们转成空格。</p><h2 id="三、top-和-htop" tabindex="-1">三、top 和 htop <a class="header-anchor" href="#三、top-和-htop" aria-label="Permalink to &quot;三、top 和 htop&quot;">​</a></h2><p><code>top</code> 提供实时的进程信息刷新：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">top</span></span></code></pre></div><p><code>top</code> 界面中的常用交互键：</p><table tabindex="0"><thead><tr><th>键</th><th>功能</th></tr></thead><tbody><tr><td><code>P</code></td><td>按 CPU 使用率排序</td></tr><tr><td><code>M</code></td><td>按内存使用率排序</td></tr><tr><td><code>1</code></td><td>展开显示每个 CPU 核心</td></tr><tr><td><code>k</code></td><td>kill 指定进程（会提示输入 PID）</td></tr><tr><td><code>q</code></td><td>退出</td></tr></tbody></table><p><code>htop</code> 是 <code>top</code> 的增强版本，支持鼠标操作、颜色显示和更直观的进程树。不一定默认安装：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> htop</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # RHEL 系</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> htop</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # Debian 系</span></span></code></pre></div><p>CPU 使用率飙高时，先 <code>top</code> 定位进程，然后看该进程内的线程分布：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">top</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -H</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pi</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>Java、Go、Node.js 这类多线程服务排 CPU 瓶颈时，看线程级别比看进程级别更有效。</p><h2 id="四、信号和-kill" tabindex="-1">四、信号和 kill <a class="header-anchor" href="#四、信号和-kill" aria-label="Permalink to &quot;四、信号和 kill&quot;">​</a></h2><p>信号是 Linux 进程间通信的一种方式，最常用的场景是通知进程终止或重新加载配置。</p><table tabindex="0"><thead><tr><th>信号</th><th>编号</th><th>含义</th></tr></thead><tbody><tr><td>SIGTERM</td><td>15</td><td>请求进程正常退出（可被进程捕获并处理）</td></tr><tr><td>SIGKILL</td><td>9</td><td>强制终止（不可被捕获，内核直接终止进程）</td></tr><tr><td>SIGHUP</td><td>1</td><td>常用于通知进程重新加载配置</td></tr></tbody></table><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">kill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1234</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # 默认发送 SIGTERM（15）</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">kill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -15</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1234</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">kill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -9</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1234</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 强制终止</span></span></code></pre></div><p>SIGTERM 是&quot;请你自己停掉&quot;——进程收到后可以清理临时文件、关闭连接、释放资源再退出。SIGKILL 是内核直接终止进程，进程没有机会做任何清理。如果某个服务经常需要用 <code>kill -9</code> 才能停，说明它的信号处理和退出逻辑可能有问题。</p><p>按名称操作进程：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pkill</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">             # 向所有名为 nginx 的进程发 SIGTERM</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pgrep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 先看有哪些匹配的进程</span></span></code></pre></div><p><code>pkill</code> 的匹配范围可能比预期大——<code>pkill nginx</code> 可能也匹配到 <code>nginx-exporter</code> 之类的进程。执行前先 <code>pgrep -a</code> 看清楚匹配结果。</p><h2 id="五、前台和后台任务" tabindex="-1">五、前台和后台任务 <a class="header-anchor" href="#五、前台和后台任务" aria-label="Permalink to &quot;五、前台和后台任务&quot;">​</a></h2><p>在 Shell 中，命令默认在前台运行，会阻塞 Shell 直到执行完成。可以在命令末尾加 <code>&amp;</code> 放到后台：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sleep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">jobs</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # 查看当前 Shell 的后台任务</span></span></code></pre></div><p>前后台切换：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">fg</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> %1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">               # 把编号为 1 的后台任务切回前台</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Ctrl+z</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # 暂停当前前台任务</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">bg</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> %1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">               # 继续在后台运行被暂停的任务</span></span></code></pre></div><p>临时命令用 <code>&amp;</code> 或 <code>Ctrl+z</code> 处理没问题。但长期运行的任务靠 <code>&amp;</code> 管理有隐患：SSH 断开后进程可能被 HUP 信号终止、输出没地方去、进程状态靠记忆追踪。长期任务建议按场景选工具：</p><table tabindex="0"><thead><tr><th>场景</th><th>合适的工具</th></tr></thead><tbody><tr><td>临时长命令</td><td>tmux / screen</td></tr><tr><td>服务进程</td><td>systemd</td></tr><tr><td>容器服务</td><td>容器运行时 / Kubernetes</td></tr><tr><td>定时任务</td><td>systemd timer / cron</td></tr></tbody></table><h2 id="六、systemd" tabindex="-1">六、systemd <a class="header-anchor" href="#六、systemd" aria-label="Permalink to &quot;六、systemd&quot;">​</a></h2><p>systemd 是目前大多数 Linux 发行版的服务管理器，负责在系统启动时按依赖关系拉起服务、监控运行状态、接管日志、在进程异常退出时按策略重启。</p><p>systemd 管理的对象叫 unit，常见的 unit 类型：</p><table tabindex="0"><thead><tr><th>类型</th><th>用途</th></tr></thead><tbody><tr><td><code>.service</code></td><td>定义服务进程</td></tr><tr><td><code>.timer</code></td><td>定时触发，替代 cron 的另一种方式</td></tr><tr><td><code>.socket</code></td><td>基于 socket 激活服务（先监听再按需启动）</td></tr><tr><td><code>.mount</code></td><td>管理挂载点</td></tr><tr><td><code>.target</code></td><td>一组 unit 的集合，相当于运行级别的概念</td></tr></tbody></table><p>查看服务状态：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> is-active</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 只看是否在运行</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> is-enabled</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # 只看是否设了开机自启</span></span></code></pre></div><p>启动和停止：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reload</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">             # 重新加载配置（不重启进程）</span></span></code></pre></div><p>开机自启：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">             # 设为开机自启</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> disable</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">            # 取消开机自启</span></span></code></pre></div><p>查看服务日志：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">journalctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                          # 持续跟踪</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">journalctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --since</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;1 hour ago&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 只看最近一小时</span></span></code></pre></div><p>服务启动失败的排查流程：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service-name</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-pager</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 看当前状态和最后几行日志</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">journalctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service-name</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-pager</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 看最近 100 行日志</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service-name</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                      # 看实际加载到的 unit 内容</span></span></code></pre></div><p><code>systemctl cat</code> 比手动找 unit 文件更准确——它会把 <code>/etc/systemd/system/</code> 下的覆盖配置（drop-in）也合并显示出来。</p><h2 id="七、unit-文件" tabindex="-1">七、unit 文件 <a class="header-anchor" href="#七、unit-文件" aria-label="Permalink to &quot;七、unit 文件&quot;">​</a></h2><p>unit 文件定义了 systemd 如何管理一个服务。文件位置：</p><table tabindex="0"><thead><tr><th>路径</th><th>用途</th></tr></thead><tbody><tr><td><code>/usr/lib/systemd/system/</code>（RHEL 系）</td><td>软件包安装的 unit</td></tr><tr><td><code>/lib/systemd/system/</code>（Debian 系）</td><td>软件包安装的 unit</td></tr><tr><td><code>/etc/systemd/system/</code></td><td>自定义 unit 和覆盖配置</td></tr></tbody></table><p>一个最小可用的 service 文件：</p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># /etc/systemd/system/myapp.service</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[Unit]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=My App</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">After</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=network.target</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[Service]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=simple</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WorkingDirectory</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=/opt/myapp</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ExecStart</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=/opt/myapp/bin/app</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Restart</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=always</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RestartSec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=5</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">User</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=app</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Group</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=app</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[Install]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WantedBy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=multi-user.target</span></span></code></pre></div><p>三个段的职责：</p><table tabindex="0"><thead><tr><th>段</th><th>作用</th></tr></thead><tbody><tr><td><code>[Unit]</code></td><td>服务描述、依赖关系和启动顺序</td></tr><tr><td><code>[Service]</code></td><td>进程如何启动、停止、重启，以什么身份运行</td></tr><tr><td><code>[Install]</code></td><td><code>systemctl enable</code> 时挂在哪个 target 下面</td></tr></tbody></table><p>常用字段详解：</p><table tabindex="0"><thead><tr><th>字段</th><th>含义</th><th>备注</th></tr></thead><tbody><tr><td><code>Description</code></td><td>服务说明</td><td>在 <code>systemctl status</code> 中显示</td></tr><tr><td><code>After</code></td><td>排在哪个服务之后启动</td><td>只表示顺序，不表示依赖；对方启动失败不会影响自己</td></tr><tr><td><code>Requires</code></td><td>强依赖，对方失败则自己也会失败</td><td>适合&quot;没网络这个服务没意义&quot;的场景</td></tr><tr><td><code>Wants</code></td><td>弱依赖，对方失败不影响自己</td><td>适合&quot;对方在最好，没有也能接受&quot;</td></tr><tr><td><code>Type</code></td><td>进程启动类型</td><td>决定了 systemd 怎么判断服务是否&quot;已启动&quot;</td></tr><tr><td><code>ExecStart</code></td><td>启动命令</td><td>写绝对路径，systemd 的 PATH 和登录 Shell 不同</td></tr><tr><td><code>Restart</code></td><td>退出后的重启策略</td><td><code>always</code> / <code>on-failure</code> / <code>no</code></td></tr><tr><td><code>RestartSec</code></td><td>重启前等待时间</td><td>防止失败后疯狂重启</td></tr><tr><td><code>User</code> / <code>Group</code></td><td>以哪个用户身份运行</td><td>服务长期用 root 跑，风险偏高</td></tr><tr><td><code>EnvironmentFile</code></td><td>从这里读取环境变量</td><td>端口、路径、密钥等配置适合放单独文件</td></tr><tr><td><code>WantedBy</code></td><td><code>enable</code> 时的挂载目标</td><td>通常用 <code>multi-user.target</code></td></tr></tbody></table><p><code>Type</code> 的选择直接影响 systemd 能否正确判断服务状态：</p><table tabindex="0"><thead><tr><th>Type</th><th>适用情况</th></tr></thead><tbody><tr><td><code>simple</code></td><td>程序以前台方式运行，启动即就绪（最常见）</td></tr><tr><td><code>forking</code></td><td>程序自己 fork 到后台（老式守护进程常用）</td></tr><tr><td><code>oneshot</code></td><td>任务执行完就退出，用于初始化脚本</td></tr><tr><td><code>notify</code></td><td>程序主动通过 socket 通知 systemd&quot;我已就绪&quot;</td></tr></tbody></table><p>现在写服务优先让程序以前台方式运行，用 <code>Type=simple</code>。把守护化（daemonize）交给 systemd 管，日志和退出状态更好追踪。</p><p>编写和启用的流程：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vim</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/systemd/system/myapp.service</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> daemon-reload</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 让 systemd 重新读取 unit 文件</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> myapp</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> myapp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-pager</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> myapp</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 设置开机自启</span></span></code></pre></div><p>修改 unit 后同样需要 <code>systemctl daemon-reload</code> 再 <code>restart</code>。</p><p>常见启动失败的排查：</p><table tabindex="0"><thead><tr><th>现象</th><th>常见原因</th></tr></thead><tbody><tr><td>手动执行正常，systemd 启动失败</td><td>缺少环境变量、工作目录不对、路径不是绝对路径</td></tr><tr><td>服务启动后立刻 failed</td><td>程序自己退出了，或者 <code>Type</code> 写错</td></tr><tr><td>修改 unit 后不生效</td><td>忘了 <code>systemctl daemon-reload</code></td></tr><tr><td>服务反复重启</td><td><code>Restart=always</code> 配合程序快速失败</td></tr><tr><td>日志找不到</td><td>程序把日志写到了文件而不是 stdout/stderr，或者 journald 配置了不持久化</td></tr></tbody></table>`,77)])])}const g=i(n,[["render",p]]);export{c as __pageData,g as default};
